const crypto = require('crypto');
const item = $input.first().json || {};
const headers = item.headers || {};
const body = item.body || {};
const secret = String($env.N8N_ERP_OUTBOUND_HMAC_SECRET || '').trim();
if (!secret) throw new Error('Missing N8N_ERP_OUTBOUND_HMAC_SECRET');
const incomingRaw = String(headers['x-erp-signature'] || headers['X-ERP-Signature'] || '').trim();
const incoming = incomingRaw.replace(/^sha256=/i, '');
if (!incoming) throw new Error('Missing x-erp-signature');
const normalizedBody = JSON.stringify(body);
const expected = crypto.createHmac('sha256', secret).update(normalizedBody).digest('hex');
const expectedBuf = Buffer.from(expected, 'hex');
const incomingBuf = Buffer.from(incoming, 'hex');
if (!expectedBuf.length || expectedBuf.length !== incomingBuf.length || !crypto.timingSafeEqual(expectedBuf, incomingBuf)) {
  throw new Error('Invalid x-erp-signature');
}
const eventId = String(body.eventId || '').trim();
if (!eventId) throw new Error('Missing eventId');
const staticData = getWorkflowStaticData('global');
if (!staticData.aiRouterSeen) staticData.aiRouterSeen = {};
const now = Date.now();
for (const [key, value] of Object.entries(staticData.aiRouterSeen)) {
  if (typeof value === 'number' && now - value > 3 * 24 * 60 * 60 * 1000) {
    delete staticData.aiRouterSeen[key];
  }
}
if (staticData.aiRouterSeen[eventId]) return [];
staticData.aiRouterSeen[eventId] = now;
const industryKey = String(body.industryKey || 'default').trim().toLowerCase();
return [{ json: { eventId, industryKey, payload: body } }];

