const crypto = require('crypto');
const rec = $input.first().json || {};
const payload = rec.payload || {};
const cfg = rec.industryConfig || {};
const startedAt = Date.now();

const trimRightSlash = (value) => (value.endsWith('/') ? value.slice(0, -1) : value);
const context = payload.context || {};
const transcript = Array.isArray(context.transcript) ? context.transcript.join('\n') : '';
const latestMessages = Array.isArray(context.latestMessages) ? context.latestMessages : [];
const customer = context.customer || {};

let knowledgeSnippet = '';
const knowledgeBase = trimRightSlash(String($env.KNOWLEDGE_SERVICE_URL || ''));
const knowledgeSpaceRef = String(payload.knowledgeSpaceRef || '').trim();
if (knowledgeBase && knowledgeSpaceRef) {
  try {
    const question = latestMessages.length > 0
      ? String(latestMessages[latestMessages.length - 1].content || '').slice(0, 500)
      : '';
    const kRes = await fetch(knowledgeBase + '/retrieve', {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({ spaceRef: knowledgeSpaceRef, query: question, topK: 3 }),
    });
    if (kRes.ok) {
      const kJson = await kRes.json();
      if (Array.isArray(kJson.items)) {
        knowledgeSnippet = kJson.items
          .map((x) => String(x.content || '').trim())
          .filter(Boolean)
          .join('\n\n')
          .slice(0, 4000);
      } else if (typeof kJson.summary === 'string') {
        knowledgeSnippet = kJson.summary.slice(0, 4000);
      }
    }
  } catch (err) {
    // Do not hard-fail knowledge lookup.
  }
}

let replyText = '';
let tokenUsage = null;
let shouldHandoff = false;
let errorReason = '';

try {
  const aiBase = trimRightSlash(String($env.AI_OPENAI_COMPAT_BASE_URL || ''));
  const aiKey = String($env.AI_OPENAI_COMPAT_API_KEY || '').trim();
  const model = String(cfg.model || $env.AI_OPENAI_COMPAT_MODEL || 'gpt-4o-mini');
  if (!aiBase || !aiKey) throw new Error('Missing AI_OPENAI_COMPAT config');

  const userPrompt = [
    'Industry: ' + String(cfg.industryKey || payload.industryKey || 'default'),
    'ThreadId: ' + String(payload.threadId || ''),
    'Customer: ' + String(customer.fullName || ''),
    'Recent transcript:',
    transcript,
    '',
    'Knowledge:',
    knowledgeSnippet || '(none)',
  ].join('\n');

  const aiRes = await fetch(aiBase + '/chat/completions', {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      authorization: 'Bearer ' + aiKey,
    },
    body: JSON.stringify({
      model,
      messages: [
        { role: 'system', content: String(cfg.systemPrompt || 'Bạn là trợ lý CSKH chuyên nghiệp.') },
        { role: 'user', content: userPrompt },
      ],
      temperature: 0.2,
      max_tokens: 400,
    }),
  });

  if (!aiRes.ok) throw new Error('AI_HTTP_' + aiRes.status);
  const aiJson = await aiRes.json();
  replyText = String(aiJson.choices?.[0]?.message?.content || '').trim();
  tokenUsage = aiJson.usage || null;
  if (!replyText) throw new Error('EMPTY_AI_REPLY');
} catch (err) {
  shouldHandoff = true;
  errorReason = String(err?.message || err || 'AI_CALL_FAILED');
}

const callbackPayload = {
  eventId: String(payload.eventId || rec.eventId || ''),
  replyText: shouldHandoff ? null : replyText,
  confidence: shouldHandoff ? null : 0.72,
  workflowKey: String(payload.workflowKey || cfg.workflowKey || '') || null,
  agentKey: String(cfg.agentKey || payload.agentKey || '') || null,
  tokenUsage,
  latencyMs: Date.now() - startedAt,
  safetyFlags: {
    knowledgeUsed: Boolean(knowledgeSnippet),
    errorReason: errorReason || null,
  },
  shouldHandoff,
};

const erpBase = trimRightSlash(String($env.ERP_API_BASE_URL || ''));
const callbackSecret = String($env.N8N_ERP_CALLBACK_HMAC_SECRET || '').trim();
if (!erpBase) throw new Error('Missing ERP_API_BASE_URL');
if (!callbackSecret) throw new Error('Missing N8N_ERP_CALLBACK_HMAC_SECRET');

const callbackBody = JSON.stringify(callbackPayload);
const callbackSig = crypto.createHmac('sha256', callbackSecret).update(callbackBody).digest('hex');
const cbRes = await fetch(erpBase + '/api/v1/integrations/n8n/ai-replies', {
  method: 'POST',
  headers: {
    'content-type': 'application/json',
    'x-n8n-signature': 'sha256=' + callbackSig,
  },
  body: callbackBody,
});
const cbText = await cbRes.text();

return [{
  json: {
    eventId: callbackPayload.eventId,
    industryKey: rec.industryKey,
    callbackStatus: cbRes.status,
    callbackBody: cbText.slice(0, 1000),
    shouldHandoff,
    errorReason: errorReason || null,
  },
}];
